import anthropic

client = anthropic.Anthropic()


def call(prompt: str, max_tokens: int = 350) -> str:
    return client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=max_tokens,
        temperature=0.0,
        messages=[{"role": "user", "content": prompt}],
    ).content[0].text.strip()


def cot_answer(question: str) -> str:
    return call(f"{question}\nLet's think step by step.")


def step_back_answer(question: str, abstract_q: str) -> str:
    principle = call(
        f"Answer this general question in 2 sentences:\n{abstract_q}"
    )
    return call(
        f"Principle: {principle}\n\n"
        f"Using this principle, answer concisely:\n{question}"
    )


# Questions where the two techniques should behave differently
TASKS = [
    {
        "question": "A train travels 120 km in 1.5 hours. What is its average speed?",
        "abstract_q": "What is the formula for calculating average speed?",
        "type": "arithmetic",
    },
    {
        "question": "Why does copper turn green when exposed to air and moisture over time?",
        "abstract_q": "What chemical reaction occurs when copper is exposed to oxygen and moisture?",
        "type": "factual/causal",
    },
    {
        "question": "If 30% of 200 students passed, how many failed?",
        "abstract_q": "How do you calculate a percentage of a total and find the remainder?",
        "type": "arithmetic",
    },
]

for task in TASKS:
    print(f"[{task['type']}] {task['question']}")
    print(f"CoT:        {cot_answer(task['question'])[:200]}")
    print(f"Step-back:  {step_back_answer(task['question'], task['abstract_q'])[:200]}")
    print()

import anthropic
from enum import Enum

client = anthropic.Anthropic()

class Strategy(Enum):
    DIRECT = "direct"
    COT    = "cot"
    STEP_BACK = "step_back"
    COMBINED  = "combined"

def _call(prompt: str, max_tokens: int = 400) -> str:
    return client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=max_tokens,
        temperature=0.0,
        messages=[{"role": "user", "content": prompt}],
    ).content[0].text.strip()

def answer(question: str, abstract_q: str | None, strategy: Strategy) -> dict:
    """
    Dispatch to the appropriate prompting strategy.
    abstract_q is required for STEP_BACK and COMBINED strategies.
    """
    if strategy == Strategy.DIRECT:
        return {"answer": _call(question)}

    if strategy == Strategy.COT:
        raw = _call(f"{question}\nLet\'s think step by step.")
        return {"reasoning": raw, "answer": raw.split("\n")[-1]}

    if strategy == Strategy.STEP_BACK:
        principle = _call(
            f"Answer this general question concisely (2 sentences):\n{abstract_q}"
        )
        ans = _call(
            f"Principle: {principle}\n\nNow answer this specific question:\n{question}"
        )
        return {"principle": principle, "answer": ans}

    if strategy == Strategy.COMBINED:
        principle = _call(
            f"State the formula or principle needed (2 sentences):\n{abstract_q}"
        )
        reasoning = _call(
            f"Principle: {principle}\n\nApply it step by step to:\n{question}"
        )
        return {"principle": principle, "reasoning": reasoning,
                "answer": reasoning.split("\n")[-1]}

    raise ValueError(f"Unknown strategy: {strategy}")

# Example usage
q = "A solution is prepared by dissolving 5.85 g of NaCl (MW=58.5) in 500 mL of water. What is the molarity?"
result = answer(
    question=q,
    abstract_q="What is the formula for calculating molarity of a solution?",
    strategy=Strategy.COMBINED,
)
print(result)
